from collections import deque

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    original_adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, cost in edges:
        original_adj[u].append((v, cost))
        in_degree[v] += 1

    # Kahn's algorithm for topological sort
    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)
    top_order = []
    while q:
        u = q.popleft()
        top_order.append(u)
        for v, _ in original_adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Find maximum edge cost
    max_cost = 0
    for u, v, cost in edges:
        if cost > max_cost:
            max_cost = cost

    low, high = 0, max_cost
    answer = -1

    while low <= high:
        mid = (low + high) // 2
        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        for u in top_order:
            if dist[u] == INF:
                continue
            if not online[u]:
                continue
            for (v, cost) in original_adj[u]:
                if online[v] and cost >= mid:
                    if dist[v] > dist[u] + cost:
                        dist[v] = dist[u] + cost
        if dist[n-1] <= k:
            answer = mid
            low = mid + 1
        else:
            high = mid - 1

    return answer if answer != -1 else -1
