import heapq

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    for u, v, cost in edges:
        if online[v]:
            adj[u].append((v, cost))
    dp = [-float('inf')] * n
    dp[0] = float('inf')
    heap = [(-float('inf'), 0, 0)]
    while heap:
        neg_current_min, total_cost, u = heapq.heappop(heap)
        current_min = -neg_current_min
        if u == n - 1:
            return current_min
        for v, cost in adj[u]:
            new_min = min(current_min, cost)
            new_total = total_cost + cost
            if new_total > k:
                continue
            if new_min > dp[v]:
                dp[v] = new_min
                heapq.heappush(heap, (-new_min, new_total, v))
    return -1
